#!/usr/bin/perl
use strict;
use warnings;
use File::Slurp;

# Read plugin code from configuration file
my $config_file = shift || 'plugin_config.txt';
my @plugin_files = read_file($config_file);

# Execute each plugin
foreach my $plugin_file (@plugin_files) {
    chomp $plugin_file;
    next if $plugin_file =~ /^\s*$/;  # Skip empty lines
    
    # Read plugin code
    my $plugin_code = read_file($plugin_file);
    
    # Validate plugin code - check for dangerous patterns
    if ($plugin_code =~ /system\s*\(|exec\s*\(|`.*`|eval\s*\(|require\s*\(|use\s+Socket|use\s+IO::Socket|use\s+File::|use\s+IPC::|use\s+DBI|use\s+DBD/ix) {
        warn "Security violation detected in plugin $plugin_file\n";
        next;
    }
    
    # Execute plugin code
    eval {
        my $result = eval $plugin_code;
        if ($@) {
            warn "Plugin execution failed: $@\n";
        } else {
            print "Plugin executed successfully\n";
        }
    };
    
    if ($@) {
        warn "Error executing plugin: $@\n";
    }
}

